        code: `function rotateRight(
  head: ListNode | null,
  k: number,
): ListNode | null {
  if (!head || !head.next || k === 0) {
    return head
  }

  let length = 1
  let tail = head

  while (tail.next) {
    tail = tail.next
    length += 1
  }

  const offset = k % length

  if (offset === 0) {
    return head
  }

  tail.next = head

  let stepsToNewTail = length - offset - 1
  let newTail = head

  while (stepsToNewTail > 0) {
    newTail = newTail.next!
    stepsToNewTail -= 1
  }

  const newHead = newTail.next
  newTail.next = null

  return newHead
}`,
