  const states: Array<Record<string, number>> = [
    { space: 0, sign: 1, digit: 2, dot: 4 },
    { digit: 2, dot: 4 },
    { digit: 2, dot: 3, exp: 5, space: 8 },
    { digit: 3, exp: 5, space: 8 },
    { digit: 3 },
    { sign: 6, digit: 7 },
    { digit: 7 },
    { digit: 7, space: 8 },
    { space: 8 },
  ]

