        code: `function sortList(head: ListNode | null): ListNode | null {
  if (!head || !head.next) {
    return head
  }

  let slow = head
  let fast = head.next

  while (fast && fast.next) {
    slow = slow.next!
    fast = fast.next.next
  }

  const rightHead = slow.next
  slow.next = null

  const left = sortList(head)
  const right = sortList(rightHead)

  return merge(left, right)
}

function merge(
  left: ListNode | null,
  right: ListNode | null,
): ListNode | null {
  const dummy = new ListNode(0)
  let tail = dummy

  while (left && right) {
    if (left.val <= right.val) {
      tail.next = left
      left = left.next
    } else {
      tail.next = right
      right = right.next
    }

    tail = tail.next
  }

  tail.next = left || right
  return dummy.next
}`,
