        code: `function kthSmallest(root: TreeNode | null, k: number): number {
  let count = 0
  let answer = 0

  const inorder = (node: TreeNode | null): void => {
    if (node === null || count >= k) {
      return
    }

    inorder(node.left)

    if (count >= k) {
      return
    }

    count += 1

    if (count === k) {
      answer = node.val
      return
    }

    inorder(node.right)
  }

  inorder(root)
  return answer
}`,
