        code: `function countDigitOne(n: number): number {
  let count = 0

  for (let factor = 1; factor <= n; factor *= 10) {
    const low = n % factor
    const current = Math.floor(n / factor) % 10
    const high = Math.floor(n / (factor * 10))

    if (current === 0) {
      count += high * factor
    } else if (current === 1) {
      count += high * factor + low + 1
    } else {
      count += (high + 1) * factor
    }
  }

  return count
}`,
