        code: `function countNumbersWithUniqueDigits(n: number): number {
  if (n === 0) {
    return 1
  }

  let total = 10
  let current = 9
  let available = 9

  for (let digits = 2; digits <= n && available > 0; digits += 1) {
    current *= available
    total += current
    available -= 1
  }

  return total
}`,
