        code: `function removeKdigits(num: string, k: number): string {
  const stack: string[] = []
  let remaining = k

  for (const digit of num) {
    while (remaining > 0 && stack.length > 0 && stack[stack.length - 1] > digit) {
      stack.pop()
      remaining -= 1
    }

    stack.push(digit)
  }

  while (remaining > 0) {
    stack.pop()
    remaining -= 1
  }

  const result = stack.join('').replace(/^0+/, '')
  return result === '' ? '0' : result
}`,
