  let i = 0
  let j = 0

  while (i < word.length && j < abbr.length) {
    const char = abbr[j]

    if (char >= '0' && char <= '9') {
      if (char === '0') {
        return false
      }

      let count = 0

      while (j < abbr.length && abbr[j] >= '0' && abbr[j] <= '9') {
        count = count * 10 + Number(abbr[j])
        j += 1
      }

      i += count
      continue
    }

    if (word[i] !== char) {
      return false
    }

    i += 1
    j += 1
  }

  return i === word.length && j === abbr.length
