        code: `function compress(chars: string[]): number {
  let write = 0
  let read = 0

  while (read < chars.length) {
    const current = chars[read]
    let start = read

    while (read < chars.length && chars[read] === current) {
      read += 1
    }

    chars[write] = current
    write += 1

    const count = read - start

    if (count > 1) {
      for (const digit of String(count)) {
        chars[write] = digit
        write += 1
      }
    }
  }

  return write
}`,
