        code: `function findPermutation(s: string): number[] {
  const answer = Array.from({ length: s.length + 1 }, (_, index) => index + 1)

  let index = 0
  while (index < s.length) {
    if (s[index] !== 'D') {
      index += 1
      continue
    }

    const left = index
    while (index < s.length && s[index] === 'D') {
      index += 1
    }

    let start = left
    let end = index
    while (start < end) {
      ;[answer[start], answer[end]] = [answer[end], answer[start]]
      start += 1
      end -= 1
    }
  }

  return answer
}`,
