        code: `function reversePairs(nums: number[]): number {
  const temp = new Array<number>(nums.length).fill(0)

  const mergeSort = (left: number, right: number): number => {
    if (left >= right) {
      return 0
    }

    const mid = Math.floor((left + right) / 2)
    let count = mergeSort(left, mid) + mergeSort(mid + 1, right)

    let j = mid + 1
    for (let i = left; i <= mid; i += 1) {
      while (j <= right && nums[i] > 2 * nums[j]) {
        j += 1
      }
      count += j - (mid + 1)
    }

    let i = left
    j = mid + 1
    let index = left

    while (i <= mid && j <= right) {
      if (nums[i] <= nums[j]) {
        temp[index] = nums[i]
        i += 1
      } else {
        temp[index] = nums[j]
        j += 1
      }
      index += 1
    }

    while (i <= mid) {
      temp[index] = nums[i]
      i += 1
      index += 1
    }

    while (j <= right) {
      temp[index] = nums[j]
      j += 1
      index += 1
    }

    for (let p = left; p <= right; p += 1) {
      nums[p] = temp[p]
    }

    return count
  }

  return mergeSort(0, nums.length - 1)
}`,
