        code: `function checkPerfectNumber(num: number): boolean {
  if (num <= 1) {
    return false
  }

  let sum = 1

  for (let divisor = 2; divisor * divisor <= num; divisor += 1) {
    if (num % divisor !== 0) {
      continue
    }

    sum += divisor
    const other = num / divisor
    if (other !== divisor) {
      sum += other
    }
  }

  return sum === num
}`,
