        code: `class Node {
  val: number
  left: Node | null
  right: Node | null
  parent: Node | null

  constructor(
    val = 0,
    left: Node | null = null,
    right: Node | null = null,
    parent: Node | null = null,
  ) {
    this.val = val
    this.left = left
    this.right = right
    this.parent = parent
  }
}

function inorderSuccessor(node: Node | null): Node | null {
  if (!node) {
    return null
  }

  if (node.right) {
    let current = node.right
    while (current.left) {
      current = current.left
    }
    return current
  }

  let current = node
  while (current.parent && current.parent.right === current) {
    current = current.parent
  }

  return current.parent
}`,
