  const sum = machines.reduce((total, value) => total + value, 0)
  const n = machines.length

  if (sum % n !== 0) {
    return -1
  }

  const average = sum / n
  let answer = 0
  let prefix = 0

  for (const machine of machines) {
    const load = machine - average
    prefix += load
    answer = Math.max(answer, Math.abs(prefix), load)
  }

  return answer
